// Define content topics and niches to research
// Customize these topics for your business
const topics = [
  { niche: 'freight', keywords: ['freight forwarding thailand', 'นำเข้าส่งออก', 'logistics startup'], platform: 'YouTube Shorts' },
  { niche: 'real_estate', keywords: ['อสังหาริมทรัพย์ 2024', 'condo investment thailand', 'ซื้อบ้านฉลาด'], platform: 'YouTube' },
  { niche: 'sauna', keywords: ['sauna health benefits', 'สวนสุขภาพ', 'wellness thailand'], platform: 'TikTok' },
  { niche: 'business', keywords: ['ธุรกิจขนาดเล็ก automation', 'AI business tools', 'make money online thailand'], platform: 'YouTube Shorts' }
];

const week = Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));

return topics.map(t => ({
  json: {
    ...t,
    researchWeek: week,
    researchDate: new Date().toISOString().slice(0, 10)
  }
}));

