parameters.jsCode:
// Parse GPT response and prepare for Google Sheets
const topic = $('Define Weekly Research Topics').first().json;
const gptResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';

let parsed = {};
try {
  const jsonMatch = gptResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  parsed = { titles: [gptResponse.slice(0, 100)], hook: '', outline: [], cta: '', hashtags: [] };
}

const now = new Date();
const contentId = `CONT-${now.getFullYear()}-${Math.floor(1000 + Math.random() * 9000)}`;

const publishDate = new Date();
publishDate.setDate(publishDate.getDate() + (topic.platform === 'YouTube' ? 10 : 5));

return [{
  json: {
    contentId,
    week: `W${topic.researchWeek}`,
    publishDate: publishDate.toISOString().slice(0, 10),
    platform: topic.platform,
    niche: topic.niche,
    suggestedTitle: (parsed.titles || [])[0] || 'TBD',
    allTitles: (parsed.titles || []).join(' | '),
    hook: parsed.hook || '',
    outline: (parsed.outline || []).join('\n'),
    cta: parsed.cta || '',
    hashtags: (parsed.hashtags || []).join(' '),
    scriptStatus: 'Draft',
    productionStatus: 'Not Started',
    researchDate: topic.researchDate
  }
}];

