// Find content ready for final approval (production done, not yet published)
const today = new Date().toISOString().slice(0, 10);
const rows = $input.all().map(r => r.json);

const readyItems = rows.filter(row => {
  const productionStatus = (row['Production Status'] || '').toString();
  const publishedLink = (row['Published Link'] || '').toString();
  const publishDate = (row['Publish Date'] || '').toString().slice(0, 10);
  return productionStatus === 'Ready for Review'
    && !publishedLink
    && publishDate <= today;
});

return readyItems.map(r => ({ json: r }));

